import { useState, useEffect } from "react";
import { useNavigate } from "react-router-dom";
import { ArrowLeft, Save, Sparkles, Play, Check, Info, Link2, ShoppingBag, UtensilsCrossed } from "lucide-react";
import { Button } from "@/components/ui/button";
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from "@/components/ui/card";
import { Label } from "@/components/ui/label";
import { Switch } from "@/components/ui/switch";
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "@/components/ui/select";
import { Badge } from "@/components/ui/badge";
import { toast } from "sonner";
import { useSiteSettings } from "@/hooks/useSiteSettings";
import { LovableAIDemoDialog } from "@/components/admin/LovableAIDemoDialog";

const AVAILABLE_MODELS = [
  { 
    value: "google/gemini-3-flash-preview", 
    label: "Gemini 3 Flash Preview", 
    description: "最新一代模型，平衡速度与能力",
    recommended: true,
  },
  { 
    value: "google/gemini-2.5-flash", 
    label: "Gemini 2.5 Flash", 
    description: "平衡选择：成本低、延迟低，多模态和推理能力良好",
  },
  { 
    value: "google/gemini-2.5-flash-lite", 
    label: "Gemini 2.5 Flash Lite", 
    description: "最快最便宜，适合简单任务",
  },
  { 
    value: "google/gemini-2.5-pro", 
    label: "Gemini 2.5 Pro", 
    description: "顶级模型：最强推理和多模态能力，但成本较高",
  },
  { 
    value: "google/gemini-3-pro-preview", 
    label: "Gemini 3 Pro Preview", 
    description: "下一代 Pro 模型预览版",
  },
  { 
    value: "openai/gpt-5-mini", 
    label: "GPT-5 Mini", 
    description: "OpenAI 中端模型：性价比高",
  },
  { 
    value: "openai/gpt-5-nano", 
    label: "GPT-5 Nano", 
    description: "OpenAI 轻量模型：速度快、成本低",
  },
  { 
    value: "openai/gpt-5", 
    label: "GPT-5", 
    description: "OpenAI 顶级模型：最强推理能力，成本最高",
  },
];

export default function AdminLovableAIConfig() {
  const navigate = useNavigate();
  const { settings, isLoading, updateSettings } = useSiteSettings();
  const [demoOpen, setDemoOpen] = useState(false);
  const [selectedModel, setSelectedModel] = useState("google/gemini-3-flash-preview");
  const [isEnabled, setIsEnabled] = useState(true);
  const [showLinks, setShowLinks] = useState(true);
  const [isSaving, setIsSaving] = useState(false);

  useEffect(() => {
    if (settings) {
      setSelectedModel(settings.lovable_ai_model_name || "google/gemini-3-flash-preview");
      setIsEnabled(settings.lovable_ai_enabled ?? true);
      setShowLinks(settings.lovable_ai_show_links ?? true);
    }
  }, [settings]);

  const handleSave = async () => {
    setIsSaving(true);
    try {
      await updateSettings.mutateAsync({
        lovable_ai_model_name: selectedModel,
        lovable_ai_enabled: isEnabled,
        lovable_ai_show_links: showLinks,
      });
      toast.success("配置已保存，立即生效");
    } catch (error) {
      console.error("Failed to save settings:", error);
      toast.error("保存失败，请重试");
    } finally {
      setIsSaving(false);
    }
  };

  const selectedModelInfo = AVAILABLE_MODELS.find(m => m.value === selectedModel);

  if (isLoading) {
    return (
      <div className="space-y-6">
        <div className="h-8 w-48 bg-muted animate-pulse rounded" />
        <div className="h-64 bg-muted animate-pulse rounded" />
      </div>
    );
  }

  return (
    <div className="space-y-6">
      {/* Header */}
      <div className="flex items-center justify-between">
        <div className="flex items-center gap-4">
          <Button variant="ghost" size="icon" onClick={() => navigate("/admin/ai-config")}>
            <ArrowLeft className="h-4 w-4" />
          </Button>
          <div>
            <h1 className="text-2xl font-bold flex items-center gap-2">
              <Sparkles className="h-6 w-6 text-purple-500" />
              Lovable AI 配置
            </h1>
            <p className="text-muted-foreground text-sm mt-1">
              配置智能餐厅推荐助手的模型和行为
            </p>
          </div>
        </div>
        <div className="flex gap-2">
          <Button variant="outline" onClick={() => setDemoOpen(true)}>
            <Play className="h-4 w-4 mr-2" />
            测试
          </Button>
          <Button onClick={handleSave} disabled={isSaving}>
            {isSaving ? (
              <span className="animate-spin mr-2">⏳</span>
            ) : (
              <Save className="h-4 w-4 mr-2" />
            )}
            保存配置
          </Button>
        </div>
      </div>

      {/* Main Settings Card */}
      <Card>
        <CardHeader>
          <CardTitle>基本设置</CardTitle>
          <CardDescription>
            配置 Lovable AI 的核心参数
          </CardDescription>
        </CardHeader>
        <CardContent className="space-y-6">
          {/* Enable/Disable */}
          <div className="flex items-center justify-between">
            <div className="space-y-0.5">
              <Label htmlFor="enable-lovable-ai">启用 Lovable AI</Label>
              <p className="text-sm text-muted-foreground">
                开启后，用户可以使用智能餐厅推荐功能
              </p>
            </div>
            <Switch
              id="enable-lovable-ai"
              checked={isEnabled}
              onCheckedChange={setIsEnabled}
            />
          </div>

          {/* Show Links */}
          <div className="flex items-center justify-between">
            <div className="space-y-0.5">
              <Label htmlFor="show-links" className="flex items-center gap-2">
                <Link2 className="h-4 w-4" />
                显示外卖/订台链接
              </Label>
              <p className="text-sm text-muted-foreground">
                推荐餐厅时显示外卖和订台的快捷链接
              </p>
            </div>
            <Switch
              id="show-links"
              checked={showLinks}
              onCheckedChange={setShowLinks}
            />
          </div>

          {showLinks && (
            <div className="bg-muted/50 rounded-lg p-4 space-y-2">
              <p className="text-sm font-medium">链接说明</p>
              <div className="flex flex-wrap gap-3 text-sm text-muted-foreground">
                <span className="flex items-center gap-1">
                  <ShoppingBag className="h-3 w-3" />
                  外卖: takeaway_url
                </span>
                <span className="flex items-center gap-1">
                  <UtensilsCrossed className="h-3 w-3" />
                  订台: booking_url
                </span>
              </div>
              <p className="text-xs text-muted-foreground">
                * 仅当餐厅设置了对应链接且开启对应按钮时才会显示
              </p>
            </div>
          )}

          {/* Model Selection */}
          <div className="space-y-3">
            <Label>AI 模型</Label>
            <Select value={selectedModel} onValueChange={setSelectedModel}>
              <SelectTrigger className="w-full">
                <SelectValue placeholder="选择 AI 模型" />
              </SelectTrigger>
              <SelectContent>
                {AVAILABLE_MODELS.map((model) => (
                  <SelectItem key={model.value} value={model.value}>
                    <div className="flex items-center gap-2">
                      <span>{model.label}</span>
                      {model.recommended && (
                        <Badge variant="secondary" className="text-xs">推荐</Badge>
                      )}
                    </div>
                  </SelectItem>
                ))}
              </SelectContent>
            </Select>
            {selectedModelInfo && (
              <p className="text-sm text-muted-foreground flex items-center gap-1">
                <Info className="h-3 w-3" />
                {selectedModelInfo.description}
              </p>
            )}
          </div>
        </CardContent>
      </Card>

      {/* Features Card */}
      <Card>
        <CardHeader>
          <CardTitle>功能特性</CardTitle>
          <CardDescription>
            Lovable AI 内置的智能功能
          </CardDescription>
        </CardHeader>
        <CardContent>
          <div className="grid gap-4 md:grid-cols-2">
            <div className="flex items-start gap-3 p-4 rounded-lg border bg-muted/30">
              <Check className="h-5 w-5 text-green-500 mt-0.5" />
              <div>
                <h4 className="font-medium">餐厅知识库</h4>
                <p className="text-sm text-muted-foreground">
                  自动获取数据库中所有可见餐厅信息，包括名称、类型、地址、评分等
                </p>
              </div>
            </div>
            <div className="flex items-start gap-3 p-4 rounded-lg border bg-muted/30">
              <Check className="h-5 w-5 text-green-500 mt-0.5" />
              <div>
                <h4 className="font-medium">位置感知</h4>
                <p className="text-sm text-muted-foreground">
                  根据用户位置计算距离，优先推荐附近的餐厅
                </p>
              </div>
            </div>
            <div className="flex items-start gap-3 p-4 rounded-lg border bg-muted/30">
              <Check className="h-5 w-5 text-green-500 mt-0.5" />
              <div>
                <h4 className="font-medium">智能推荐</h4>
                <p className="text-sm text-muted-foreground">
                  理解用户需求，推荐最合适的餐厅；无匹配时诚实告知并推荐替代选择
                </p>
              </div>
            </div>
            <div className="flex items-start gap-3 p-4 rounded-lg border bg-muted/30">
              <Check className="h-5 w-5 text-green-500 mt-0.5" />
              <div>
                <h4 className="font-medium">多语言支持</h4>
                <p className="text-sm text-muted-foreground">
                  支持中文、英文、葡萄牙语，根据用户语言自动回复
                </p>
              </div>
            </div>
          </div>
        </CardContent>
      </Card>

      {/* Model Comparison */}
      <Card>
        <CardHeader>
          <CardTitle>模型对比</CardTitle>
          <CardDescription>
            各模型的特点和适用场景
          </CardDescription>
        </CardHeader>
        <CardContent>
          <div className="overflow-x-auto">
            <table className="w-full text-sm">
              <thead>
                <tr className="border-b">
                  <th className="text-left py-2 pr-4">模型</th>
                  <th className="text-left py-2 pr-4">速度</th>
                  <th className="text-left py-2 pr-4">质量</th>
                  <th className="text-left py-2 pr-4">成本</th>
                  <th className="text-left py-2">适用场景</th>
                </tr>
              </thead>
              <tbody>
                <tr className="border-b">
                  <td className="py-2 pr-4 font-medium">Gemini 3 Flash Preview</td>
                  <td className="py-2 pr-4">⚡⚡⚡</td>
                  <td className="py-2 pr-4">⭐⭐⭐⭐</td>
                  <td className="py-2 pr-4">💰💰</td>
                  <td className="py-2">通用推荐（默认）</td>
                </tr>
                <tr className="border-b">
                  <td className="py-2 pr-4 font-medium">Gemini 2.5 Flash</td>
                  <td className="py-2 pr-4">⚡⚡⚡</td>
                  <td className="py-2 pr-4">⭐⭐⭐</td>
                  <td className="py-2 pr-4">💰</td>
                  <td className="py-2">高并发场景</td>
                </tr>
                <tr className="border-b">
                  <td className="py-2 pr-4 font-medium">Gemini 2.5 Pro</td>
                  <td className="py-2 pr-4">⚡⚡</td>
                  <td className="py-2 pr-4">⭐⭐⭐⭐⭐</td>
                  <td className="py-2 pr-4">💰💰💰</td>
                  <td className="py-2">复杂推理、VIP用户</td>
                </tr>
                <tr className="border-b">
                  <td className="py-2 pr-4 font-medium">GPT-5 Mini</td>
                  <td className="py-2 pr-4">⚡⚡⚡</td>
                  <td className="py-2 pr-4">⭐⭐⭐⭐</td>
                  <td className="py-2 pr-4">💰💰</td>
                  <td className="py-2">平衡性价比</td>
                </tr>
                <tr>
                  <td className="py-2 pr-4 font-medium">GPT-5</td>
                  <td className="py-2 pr-4">⚡</td>
                  <td className="py-2 pr-4">⭐⭐⭐⭐⭐</td>
                  <td className="py-2 pr-4">💰💰💰💰</td>
                  <td className="py-2">最高质量要求</td>
                </tr>
              </tbody>
            </table>
          </div>
        </CardContent>
      </Card>

      {/* Demo Dialog */}
      <LovableAIDemoDialog open={demoOpen} onOpenChange={setDemoOpen} />
    </div>
  );
}
